input.new_string:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const processScenario = (scenario: any): unknown => {
  const step = scenario.steps[0];
  const item = step.items[0];
  const base = BASE_PREMIUMS[item.type];
  const premium = Math.ceil(base * 1.10) + 5;
  return { results: [{ premium }] };
};

